                    console.log(obj);
            });

如果里面有不冲突的属性 会合并在一起;如果里面有冲突的属性   后面的值会将前面的值覆盖

**12.jQuery 自动触发事件**

自动触发事件，不需要点击等任何操作便可执行. 有 trigger("事件") 和 triggerHandler("事件")，后者不会触发元素的默认行为

                // 2.元素.trigger("事件")
                $("div").trigger("click");
                // 3.元素.triggerHandler("事件")  不会触发元素的默认行为
                $("input").on("focus" , function() {
                    $(this).val("你好吗");
                })
